import { __decorate } from "tslib";
import { ChangeDetectionStrategy, Component, Input, ViewEncapsulation, } from '@angular/core';
/**
 * Skeleton placeholder animé (shimmer) pour indiquer un chargement.
 * Décoratif (`aria-hidden`).
 */
let PfSkeletonComponent = class PfSkeletonComponent {
    constructor() {
        this.variant = 'rect';
        this.width = '';
        this.height = '';
    }
    get skeletonClasses() {
        return `ds-skeleton ds-skeleton--${this.variant}`;
    }
    get cssWidth() {
        if (this.width === '')
            return null;
        return typeof this.width === 'number' ? `${this.width}px` : this.width;
    }
    get cssHeight() {
        if (this.height === '')
            return null;
        return typeof this.height === 'number' ? `${this.height}px` : this.height;
    }
    static { this.propDecorators = {
        variant: [{ type: Input }],
        width: [{ type: Input }],
        height: [{ type: Input }]
    }; }
};
PfSkeletonComponent = __decorate([
    Component({
        selector: 'pf-skeleton',
        standalone: true,
        changeDetection: ChangeDetectionStrategy.OnPush,
        encapsulation: ViewEncapsulation.None,
        template: `
    <span
      [class]="skeletonClasses"
      [style.width]="cssWidth"
      [style.height]="cssHeight"
      aria-hidden="true"
    ></span>
  `,
    })
], PfSkeletonComponent);
export { PfSkeletonComponent };
